// Solution
var validateBranchName = function(branchName, reservedNames) {
    var validChars = /^[a-zA-Z0-9-]+$/;
    if (!validChars.test(branchName)) return false;
    var reservedSet = new Set(reservedNames.map(name => name.toLowerCase()));
    return !reservedSet.has(branchName.toLowerCase());
};

